// gen-pob-bases.js — extract every gear base type → {slot, implicit} from Path of
// Building's bundled item data (Data/Bases/*.lua, auto-generated by PoB from GGG's
// game files — "(c) Grinding Gear Games"). Run on the Main PC where PoB is installed;
// commit the emitted pob-bases.js so the VM-hosted server has it too.
//
//   node gen-pob-bases.js
//
// Re-run after a league/PoB data update. This is the authoritative, local equivalent
// of poedb's "all bases + implicits" list — no scraping, no network.
const fs = require("fs");
const path = require("path");

const POB_DIR = process.env.POB_DIR || path.join(process.env.APPDATA || "", "Path of Building Community (PoE2)");
const BASES = path.join(POB_DIR, "Data", "Bases");

// PoB `type` (and `subType` for warstaves) → our gear slot id.
const TYPE_SLOT = {
  "Bow": "bow", "Crossbow": "crossbow", "Claw": "claw", "Dagger": "dagger",
  "Flail": "flail", "Spear": "spear", "Wand": "wand", "Sceptre": "sceptre",
  "One Hand Sword": "onesword", "Two Hand Sword": "twosword",
  "One Hand Axe": "oneaxe", "Two Hand Axe": "twoaxe",
  "One Hand Mace": "onemace", "Two Hand Mace": "twomace",
  "Staff": "staff", "Focus": "focus", "Shield": "shield", "Quiver": "quiver",
  "Amulet": "amulet", "Ring": "ring", "Belt": "belt",
  "Helmet": "helmet", "Body Armour": "chest", "Gloves": "gloves", "Boots": "boots",
};
const FILES = ["bow", "crossbow", "sword", "axe", "mace", "claw", "dagger", "flail",
  "spear", "staff", "wand", "sceptre", "focus", "shield", "quiver",
  "amulet", "ring", "belt", "helmet", "body", "gloves", "boots"];

const out = {};
let count = 0;
for (const f of FILES) {
  const file = path.join(BASES, f + ".lua");
  if (!fs.existsSync(file)) { console.warn("skip (missing):", f); continue; }
  const text = fs.readFileSync(file, "utf8");
  // Split into per-base blocks at each `itemBases["Name"] = {`.
  const re = /itemBases\["([^"]+)"\]\s*=\s*\{([\s\S]*?)\n\}/g;   // block ends at a flush-left `}`
  let m;
  while ((m = re.exec(text))) {
    const name = m[1], body = m[2];
    const type = (body.match(/\btype\s*=\s*"([^"]+)"/) || [])[1];
    const subType = (body.match(/\bsubType\s*=\s*"([^"]+)"/) || [])[1];
    const implicit = (body.match(/\bimplicit\s*=\s*"([^"]+)"/) || [])[1] || null;
    let slot = TYPE_SLOT[type];
    if (subType === "Warstaff") slot = "quarterstaff";   // quarterstaves: type "Staff", subType "Warstaff"
    if (slot === "shield" && /\bBuckler\b/.test(name)) slot = "buckler";   // bucklers are a distinct trade category (armour.buckler)
    if (!slot) continue;
    out[name] = implicit ? { slot, implicit } : { slot };
    count++;
  }
}

const header = "// AUTO-GENERATED by gen-pob-bases.js from Path of Building's Data/Bases (item data (c) GGG).\n" +
  "// base type name -> { slot, implicit? }. Re-run the generator after a data update; do not hand-edit.\n";
fs.writeFileSync(path.join(__dirname, "pob-bases.js"), header + "module.exports = " + JSON.stringify(out, null, 0) + ";\n");
console.log("wrote pob-bases.js:", count, "bases");
// quick sanity peek
for (const k of ["Wrapped Quarterstaff", "Gladius", "Siege Axe", "Sapphire Ring", "Gold Amulet"]) {
  if (out[k]) console.log("  ", k, "->", JSON.stringify(out[k]));
}
